// Strategy Pattern - Payment System Example
// WHY: We define a contract so the Context (PaymentProcessor) never depends on
// concrete payment classes. It only knows this interface exists.
#include <iostream>
#include <string>
#include <memory>
using namespace std;

// STEP 1: Strategy Interface (the contract)
// WHY: Abstract class with pure virtual function serves as our Strategy interface.
// C++ doesn't have "interface" keyword — this is the idiomatic equivalent.
class PaymentStrategy {
public:
    // WHY: Virtual destructor is CRITICAL in C++. Without it, deleting a Strategy
    // through a base pointer causes undefined behavior (memory leak or crash).
    virtual ~PaymentStrategy() = default;

    // WHY: Pure virtual method — forces every concrete strategy to implement pay().
    // The "= 0" means "I have no implementation. Subclasses MUST provide one."
    virtual void pay(double amount) = 0;
};

// STEP 2: Concrete Strategies (the swappable algorithms)
// WHY: Each payment method is its OWN class. This is SRP — CreditCardPayment
// knows ONLY about credit cards. If credit card logic changes, nothing else is affected.
class CreditCardPayment : public PaymentStrategy {
private:
    string cardNumber;
    string cardHolder;

public:
    // WHY: Constructor takes card-specific data. Using initializer list for efficiency.
    // std::move avoids copying strings — transfers ownership instead.
    CreditCardPayment(string number, string holder)
        : cardNumber(std::move(number)), cardHolder(std::move(holder)) {}

    // WHY: "override" tells compiler "I'm implementing the base class method."
    // If signature doesn't match, compiler gives an error. Safety net.
    void pay(double amount) override {
        cout << "Paid $" << amount << " using Credit Card: ****" 
             << cardNumber.substr(cardNumber.length() - 4) << endl;
    }
};

// WHY: Independent class. Adding PayPal required ZERO changes to CreditCardPayment.
class PayPalPayment : public PaymentStrategy {
private:
    string email;

public:
    // WHY: explicit prevents accidental implicit conversions.
    explicit PayPalPayment(string email) : email(std::move(email)) {}

    void pay(double amount) override {
        cout << "Paid $" << amount << " using PayPal: " << email << endl;
    }
};

class CryptoPayment : public PaymentStrategy {
private:
    string walletAddress;

public:
    explicit CryptoPayment(string wallet) : walletAddress(std::move(wallet)) {}

    void pay(double amount) override {
        cout << "Paid $" << amount << " using Crypto Wallet: " << walletAddress << endl;
    }
};

// STEP 3: Context (the stable shell that NEVER changes)
// WHY: This class knows NOTHING about credit cards, PayPal, or crypto.
// It only knows PaymentStrategy (the interface). That's DIP in action.
class PaymentProcessor {
private:
    // WHY: unique_ptr owns the strategy exclusively. When you set a new strategy,
    // the old one is automatically destroyed. No manual delete needed. RAII.
    unique_ptr<PaymentStrategy> strategy;

public:
    // WHY: Takes ownership via std::move. Clear ownership semantics.
    void setStrategy(unique_ptr<PaymentStrategy> newStrategy) {
        strategy = std::move(newStrategy);
    }

    // WHY: ========== THIS IS THE MAGIC LINE ==========
    // The processor delegates to whatever strategy is currently set.
    // This ONE line is why you can add 100 payment methods and NEVER change this class.
    void processPayment(double amount) {
        if (!strategy) {
            throw runtime_error("Payment strategy not set!");
        }
        strategy->pay(amount);  // <-- THE MAGIC LINE
    }
};

int main() {
    PaymentProcessor processor;

    // WHY: CLIENT decides the strategy. Not the processor. Not the strategy itself.
    processor.setStrategy(make_unique<CreditCardPayment>("4111111111111234", "Ravi Kumar"));
    processor.processPayment(99.99);

    // WHY: Swap strategy at RUNTIME. Same processor, different behavior.
    processor.setStrategy(make_unique<PayPalPayment>("ravi@email.com"));
    processor.processPayment(49.99);

    // WHY: Adding crypto? New class, zero changes to anything above.
    processor.setStrategy(make_unique<CryptoPayment>("0xABC123DEF456"));
    processor.processPayment(199.99);

    return 0;
}

