// Strategy Pattern - Payment System Example
// WHY: We define a contract so the Context (PaymentProcessor) never depends on
// concrete payment classes. It only knows this interface exists.

// STEP 1: Strategy Interface (the contract)
// WHY: Single method — every payment method, no matter how different internally,
// boils down to one action: "process this amount".
public interface PaymentStrategy {
    void pay(double amount);
}

// STEP 2: Concrete Strategies (the swappable algorithms)
// WHY: Each payment method is its OWN class. This is SRP — CreditCardPayment
// knows ONLY about credit cards. If credit card logic changes, nothing else is affected.
public class CreditCardPayment implements PaymentStrategy {
    // WHY: Credit card needs card details. These are specific to THIS strategy.
    // Other strategies don't need card numbers. Data stays encapsulated here.
    private String cardNumber;
    private String cardHolder;

    // WHY: Constructor injection — provide card details when creating the strategy.
    // The Context (PaymentProcessor) never sees these details.
    public CreditCardPayment(String cardNumber, String cardHolder) {
        this.cardNumber = cardNumber;
        this.cardHolder = cardHolder;
    }

    // WHY: The method signature matches the interface exactly (LSP).
    // The Context calls pay() and doesn't care what's underneath.
    @Override
    public void pay(double amount) {
        String masked = "****-****-****-" + cardNumber.substring(cardNumber.length() - 4);
        System.out.println("Paid $" + amount + " using Credit Card: " + masked);
    }
}

// WHY: Completely independent class. Adding PayPal required ZERO changes to
// CreditCardPayment or PaymentProcessor. This is OCP in action.
public class PayPalPayment implements PaymentStrategy {
    // WHY: PayPal needs an email, not a card number. Each strategy carries
    // only the data IT needs.
    private String email;

    public PayPalPayment(String email) {
        this.email = email;
    }

    @Override
    public void pay(double amount) {
        System.out.println("Paid $" + amount + " using PayPal: " + email);
    }
}

// WHY: 3rd payment method. We did NOT modify CreditCardPayment, PayPalPayment,
// or PaymentProcessor. We ONLY created a new file. Strategy + OCP.
public class CryptoPayment implements PaymentStrategy {
    private String walletAddress;

    public CryptoPayment(String walletAddress) {
        this.walletAddress = walletAddress;
    }

    @Override
    public void pay(double amount) {
        System.out.println("Paid $" + amount + " using Crypto: " + walletAddress);
    }
}

// STEP 3: Context (the stable shell that NEVER changes)
// WHY: This class knows NOTHING about credit cards, PayPal, or crypto.
// It only knows PaymentStrategy (the interface). That's DIP.
public class PaymentProcessor {
    // WHY: This field holds the current strategy. Its type is the INTERFACE,
    // not a concrete class. This single decision enables the entire pattern.
    private PaymentStrategy strategy;

    // WHY: Strategy is injected from outside. The processor doesn't CREATE strategies.
    public void setStrategy(PaymentStrategy strategy) {
        this.strategy = strategy;
    }

    // WHY: ========== THIS IS THE MAGIC LINE ==========
    // Delegates to whatever strategy is currently set.
    // This ONE line is why you can add 100 payment methods and NEVER change this class.
    public void processPayment(double amount) {
        if (strategy == null) {
            throw new IllegalStateException("Payment strategy not set!");
        }
        strategy.pay(amount);  // <-- THE MAGIC LINE
    }

    // STEP 4: Client code — demonstrates swapping strategies at runtime
    public static void main(String[] args) {
        PaymentProcessor processor = new PaymentProcessor();

        // CLIENT decides the strategy
        processor.setStrategy(new CreditCardPayment("4111111111111234", "Ravi Kumar"));
        processor.processPayment(99.99);

        // Swap at runtime — same processor, different behavior
        processor.setStrategy(new PayPalPayment("ravi@email.com"));
        processor.processPayment(49.99);

        // New payment method? New class, zero changes above.
        processor.setStrategy(new CryptoPayment("0xABC123DEF456"));
        processor.processPayment(199.99);
    }
}

