using namespace std;

class FormatStrategy {
public:
    virtual ~FormatStrategy() = default;
    virtual string format(const string& text) = 0;
};

class UpperCaseFormat : public FormatStrategy {
public:
    string format(const string& text) override {
        string result = text;
        transform(result.begin(), result.end(), result.begin(), ::toupper);
        return result;
    }
};

class LowerCaseFormat : public FormatStrategy {
public:
    string format(const string& text) override {
        string result = text;
        transform(result.begin(), result.end(), result.begin(), ::tolower);
        return result;
    }
};

class TitleCaseFormat : public FormatStrategy {
public:
    string format(const string& text) override {
        string result = text;
        transform(result.begin(), result.end(), result.begin(), ::tolower);
        bool capitalize = true;
        for (char& c : result) {
            if (capitalize && isalpha(c)) {
                c = toupper(c);
                capitalize = false;
            }
            if (c == ' ') capitalize = true;
        }
        return result;
    }
};

class TextEditor {
private:
    unique_ptr<FormatStrategy> strategy;
public:
    void setStrategy(unique_ptr<FormatStrategy> s) {
        strategy = std::move(s);
    }
    string applyFormat(const string& text) {
        return strategy->format(text);
    }
};

int main() {
    TextEditor editor;
    string text = "hello world from strategy pattern";

    editor.setStrategy(make_unique<UpperCaseFormat>());
    cout << editor.applyFormat(text) << endl;

    editor.setStrategy(make_unique<LowerCaseFormat>());
    cout << editor.applyFormat(text) << endl;

    editor.setStrategy(make_unique<TitleCaseFormat>());
    cout << editor.applyFormat(text) << endl;

    return 0;
}

