public interface FormatStrategy {
    String format(String text);
}

class UpperCaseFormat implements FormatStrategy {
    public String format(String text) {
        return text.toUpperCase();
    }
}

class LowerCaseFormat implements FormatStrategy {
    public String format(String text) {
        return text.toLowerCase();
    }
}

class TitleCaseFormat implements FormatStrategy {
    public String format(String text) {
        String[] words = text.toLowerCase().split(" ");
        StringBuilder sb = new StringBuilder();
        for (String word : words) {
            if (!word.isEmpty()) {
                sb.append(Character.toUpperCase(word.charAt(0)))
                  .append(word.substring(1)).append(" ");
            }
        }
        return sb.toString().trim();
    }
}

class TextEditor {
    private FormatStrategy strategy;

    public void setStrategy(FormatStrategy strategy) {
        this.strategy = strategy;
    }

    public String applyFormat(String text) {
        return strategy.format(text);
    }

    public static void main(String[] args) {
        TextEditor editor = new TextEditor();
        String text = "hello world from strategy pattern";

        editor.setStrategy(new UpperCaseFormat());
        System.out.println(editor.applyFormat(text));

        editor.setStrategy(new LowerCaseFormat());
        System.out.println(editor.applyFormat(text));

        editor.setStrategy(new TitleCaseFormat());
        System.out.println(editor.applyFormat(text));
    }
}

