// Strategy + Factory: Let the Factory decide which strategy to create
// WHY: In real systems, the client often doesn't pick the strategy manually.
// A Factory examines conditions and creates the right strategy automatically.
#include <iostream>
#include <string>
#include <memory>
using namespace std;

// Strategy Interface
class DiscountStrategy {
public:
    virtual ~DiscountStrategy() = default;
    virtual double applyDiscount(double price) = 0;
    virtual string getName() = 0;
};

// Concrete Strategies
class NoDiscount : public DiscountStrategy {
public:
    double applyDiscount(double price) override { return price; }
    string getName() override { return "No Discount"; }
};

class PercentageDiscount : public DiscountStrategy {
private:
    double percentage;
public:
    explicit PercentageDiscount(double pct) : percentage(pct) {}
    double applyDiscount(double price) override {
        return price * (1.0 - percentage / 100.0);
    }
    string getName() override {
        return to_string((int)percentage) + "% Off";
    }
};

class FlatDiscount : public DiscountStrategy {
private:
    double amount;
public:
    explicit FlatDiscount(double amt) : amount(amt) {}
    double applyDiscount(double price) override {
        return max(0.0, price - amount);
    }
    string getName() override {
        return "$" + to_string((int)amount) + " Off";
    }
};

// WHY: Factory decides which strategy based on customer type.
// The client doesn't need if-else logic — the factory encapsulates it.
class DiscountFactory {
public:
    static unique_ptr<DiscountStrategy> createDiscount(const string& customerType) {
        if (customerType == "VIP") return make_unique<PercentageDiscount>(20);
        if (customerType == "REGULAR") return make_unique<PercentageDiscount>(10);
        if (customerType == "EMPLOYEE") return make_unique<FlatDiscount>(50);
        return make_unique<NoDiscount>();
    }
};

// Context
class ShoppingCart {
private:
    unique_ptr<DiscountStrategy> discountStrategy;
    double total;
public:
    ShoppingCart() : total(0) {}
    void addItem(double price) { total += price; }
    void setDiscount(unique_ptr<DiscountStrategy> strategy) {
        discountStrategy = std::move(strategy);
    }
    double checkout() {
        if (!discountStrategy) return total;
        double finalPrice = discountStrategy->applyDiscount(total);
        cout << "Cart: $" << total << " | Discount: " 
             << discountStrategy->getName() << " | Final: $" << finalPrice << endl;
        return finalPrice;
    }
};

int main() {
    ShoppingCart cart;
    cart.addItem(100);
    cart.addItem(50);

    // Factory creates the right strategy based on customer type
    cart.setDiscount(DiscountFactory::createDiscount("VIP"));
    cart.checkout();

    cart.setDiscount(DiscountFactory::createDiscount("EMPLOYEE"));
    cart.checkout();

    cart.setDiscount(DiscountFactory::createDiscount("GUEST"));
    cart.checkout();

    return 0;
}

