class FareStrategy {
public:
    virtual ~FareStrategy() = default;
    virtual double calculateFare(double distance, int minutes) = 0;
    virtual string getName() = 0;
};

class PoolFare : public FareStrategy {
public:
    double calculateFare(double distance, int minutes) override {
        return 0.5 * distance + 0.1 * minutes;
    }
    string getName() override { return "Pool"; }
};

class RegularFare : public FareStrategy {
public:
    double calculateFare(double distance, int minutes) override {
        return 1.0 * distance + 0.2 * minutes;
    }
    string getName() override { return "Regular"; }
};

class PremiumFare : public FareStrategy {
public:
    double calculateFare(double distance, int minutes) override {
        return 2.0 * distance + 0.5 * minutes + 5.0;
    }
    string getName() override { return "Premium"; }
};

class SurgeFare : public FareStrategy {
private:
    unique_ptr<FareStrategy> baseFare;
    double multiplier;
public:
    SurgeFare(unique_ptr<FareStrategy> base, double mult)
        : baseFare(std::move(base)), multiplier(mult) {}
    double calculateFare(double distance, int minutes) override {
        return baseFare->calculateFare(distance, minutes) * multiplier;
    }
    string getName() override {
        return baseFare->getName() + " (" + to_string(multiplier) + "x surge)";
    }
};

class FareFactory {
public:
    static unique_ptr<FareStrategy> create(const string& type, double surge = 1.0) {
        unique_ptr<FareStrategy> fare;
        if (type == "POOL") fare = make_unique<PoolFare>();
        else if (type == "PREMIUM") fare = make_unique<PremiumFare>();
        else fare = make_unique<RegularFare>();
        if (surge > 1.0) return make_unique<SurgeFare>(std::move(fare), surge);
        return fare;
    }
};

