    void setFare(unique_ptr<FareStrategy> fare) { fareStrategy = std::move(fare); }
    void requestRide(double distance, int minutes) {
        double cost = fareStrategy->calculateFare(distance, minutes);
        cout << passenger << " | " << fareStrategy->getName()
             << " | " << distance << "km, " << minutes << "min | $" << cost << endl;
    }
};

int main() {
