// Advanced: Parking Lot Pricing — Strategy in a real LLD problem
// Shows Strategy + Factory + Null Object working together
#include <iostream>
#include <string>
#include <memory>
#include <ctime>
using namespace std;

// Strategy Interface for parking pricing
class PricingStrategy {
public:
    virtual ~PricingStrategy() = default;
    virtual double calculateCost(int hours, const string& vehicleType) = 0;
    virtual string getName() = 0;
};

// Hourly flat rate pricing
class HourlyPricing : public PricingStrategy {
public:
    double calculateCost(int hours, const string& vehicleType) override {
        double rate = (vehicleType == "CAR") ? 10.0 :
                      (vehicleType == "BIKE") ? 5.0 : 20.0;
        return rate * hours;
    }
    string getName() override { return "Hourly"; }
};

// Dynamic pricing — higher during peak hours
class DynamicPricing : public PricingStrategy {
private:
    double surgeMultiplier;
public:
    explicit DynamicPricing(double surge) : surgeMultiplier(surge) {}
    double calculateCost(int hours, const string& vehicleType) override {
        double baseRate = (vehicleType == "CAR") ? 10.0 :
                          (vehicleType == "BIKE") ? 5.0 : 20.0;
        return baseRate * hours * surgeMultiplier;
    }
    string getName() override {
        return "Dynamic (" + to_string(surgeMultiplier) + "x)";
    }
};

// Subscription — flat monthly rate, no per-hour charge
