        return rate * hours;
    }
    public String getName() { return "Hourly"; }
}

class DynamicPricing implements PricingStrategy {
    private double surgeMultiplier;
    public DynamicPricing(double surge) { this.surgeMultiplier = surge; }
    public double calculateCost(int hours, String vehicleType) {
        double baseRate = vehicleType.equals("CAR") ? 10.0 :
                          vehicleType.equals("BIKE") ? 5.0 : 20.0;
        return baseRate * hours * surgeMultiplier;
    }
    public String getName() { return "Dynamic (" + surgeMultiplier + "x)"; }
