#include <iostream>
#include <string>
#include <unordered_map>
#include <memory>
#include <climits>
using namespace std;

struct CacheEntry {
    string value;
    int frequency;
    int lastAccessed;
    int insertOrder;
};

class EvictionStrategy {
public:
    virtual ~EvictionStrategy() = default;
    virtual string selectEviction(const unordered_map<string, CacheEntry>& entries) = 0;
    virtual string getName() = 0;
};

class LRUEviction : public EvictionStrategy {
public:
    string selectEviction(const unordered_map<string, CacheEntry>& entries) override {
        string lruKey;
        int minTime = INT_MAX;
        for (const auto& [key, entry] : entries) {
            if (entry.lastAccessed < minTime) {
                minTime = entry.lastAccessed;
                lruKey = key;
            }
        }
        return lruKey;
    }
    string getName() override { return "LRU"; }
};

class LFUEviction : public EvictionStrategy {
public:
    string selectEviction(const unordered_map<string, CacheEntry>& entries) override {
        string lfuKey;
        int minFreq = INT_MAX;
        for (const auto& [key, entry] : entries) {
            if (entry.frequency < minFreq) {
                minFreq = entry.frequency;
                lfuKey = key;
            }
        }
        return lfuKey;
    }
    string getName() override { return "LFU"; }
};

class FIFOEviction : public EvictionStrategy {
public:
    string selectEviction(const unordered_map<string, CacheEntry>& entries) override {
        string fifoKey;
        int minOrder = INT_MAX;
        for (const auto& [key, entry] : entries) {
            if (entry.insertOrder < minOrder) {
                minOrder = entry.insertOrder;
                fifoKey = key;
            }
        }
        return fifoKey;
    }
    string getName() override { return "FIFO"; }
};

class Cache {
private:
    int maxSize;
    int clock = 0;
    int insertCounter = 0;
    unordered_map<string, CacheEntry> store;
    unique_ptr<EvictionStrategy> strategy;
public:
    Cache(int size, unique_ptr<EvictionStrategy> strat)
        : maxSize(size), strategy(std::move(strat)) {
        cout << "Cache created with " << strategy->getName() << " eviction" << endl;
    }
    string get(const string& key) {
        if (store.find(key) == store.end()) return "MISS";
        store[key].frequency++;
        store[key].lastAccessed = ++clock;
        return store[key].value;
    }
    void put(const string& key, const string& value) {
        if (store.find(key) != store.end()) {
            store[key].value = value;
            store[key].lastAccessed = ++clock;
            return;
        }
        if ((int)store.size() >= maxSize) {
            string evictKey = strategy->selectEviction(store);
            cout << "  Evicting: " << evictKey << " (" << strategy->getName() << ")" << endl;
            store.erase(evictKey);
        }
        store[key] = {value, 1, ++clock, ++insertCounter};
        cout << "  Stored: " << key << " = " << value << endl;
    }
};

int main() {
    auto cache = make_unique<Cache>(3, make_unique<LRUEviction>());
    cache->put("a", "1");
    cache->put("b", "2");
    cache->put("c", "3");
    cache->get("a");
    cache->put("d", "4"); // evicts b (least recently used)
    return 0;
}

